import posthog from 'posthog-js'

const posthogKey = import.meta.env.VITE_POSTHOG_KEY as string | undefined
const posthogHost = import.meta.env.VITE_POSTHOG_HOST as string | undefined

export const posthogEnabled = Boolean(posthogKey)

if (!posthogEnabled) {
  console.info('Missing VITE_POSTHOG_KEY — PostHog analytics is disabled.')
} else {
  posthog.init(posthogKey!, {
    api_host: posthogHost || 'https://us.i.posthog.com',
    capture_pageview: false,
    capture_pageleave: true,
    autocapture: false,
    respect_dnt: true,
    persistence: 'localStorage',
    loaded: (ph) => {
      if (import.meta.env.DEV) ph.debug()
    },
  })
}

if (posthogEnabled) {
  window.onerror = (_message, _source, _lineno, _colno, error) => {
    if (error) {
      posthog.capture('$exception', {
        $exception_message: error.message,
        $exception_type: error.name,
        $exception_stack_trace_raw: error.stack,
        $exception_source: 'window_onerror',
      })
    }
  }

  window.onunhandledrejection = (event: PromiseRejectionEvent) => {
    const error = event.reason instanceof Error ? event.reason : new Error(String(event.reason))
    posthog.capture('$exception', {
      $exception_message: error.message,
      $exception_type: error.name,
      $exception_stack_trace_raw: error.stack,
      $exception_source: 'unhandled_rejection',
    })
  }
}

export { posthog }

import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest'

// Unmock posthog-js for this file so we can test real behavior
vi.unmock('posthog-js')

const mockInit = vi.fn()
const mockDebug = vi.fn()

vi.mock('posthog-js', () => {
  const posthog = {
    init: mockInit,
    capture: vi.fn(),
    identify: vi.fn(),
    reset: vi.fn(),
    debug: mockDebug,
    register: vi.fn(),
    opt_out_capturing: vi.fn(),
    opt_in_capturing: vi.fn(),
    get_distinct_id: vi.fn(),
  }
  return { default: posthog, ...posthog }
})

describe('posthog client', () => {
  beforeEach(() => {
    vi.resetModules()
    mockInit.mockClear()
    mockDebug.mockClear()
  })

  afterEach(() => {
    vi.unstubAllEnvs()
  })

  it('exports posthogEnabled=false and skips init when VITE_POSTHOG_KEY is missing', async () => {
    vi.stubEnv('VITE_POSTHOG_KEY', '')
    const { posthogEnabled, posthog } = await import('./posthog')
    expect(posthogEnabled).toBe(false)
    expect(mockInit).not.toHaveBeenCalled()
    expect(posthog).toBeDefined()
  })

  it('exports posthogEnabled=true and calls init when VITE_POSTHOG_KEY is set', async () => {
    vi.stubEnv('VITE_POSTHOG_KEY', 'phc_test123')
    const { posthogEnabled } = await import('./posthog')
    expect(posthogEnabled).toBe(true)
    expect(mockInit).toHaveBeenCalledOnce()
    expect(mockInit).toHaveBeenCalledWith('phc_test123', expect.objectContaining({
      api_host: 'https://us.i.posthog.com',
      capture_pageview: false,
      capture_pageleave: true,
      autocapture: false,
      respect_dnt: true,
      persistence: 'localStorage',
    }))
  })

  it('uses default host when VITE_POSTHOG_HOST is absent', async () => {
    vi.stubEnv('VITE_POSTHOG_KEY', 'phc_test123')
    vi.stubEnv('VITE_POSTHOG_HOST', '')
    await import('./posthog')
    expect(mockInit).toHaveBeenCalledWith('phc_test123', expect.objectContaining({
      api_host: 'https://us.i.posthog.com',
    }))
  })

  it('uses custom host when VITE_POSTHOG_HOST is set', async () => {
    vi.stubEnv('VITE_POSTHOG_KEY', 'phc_test123')
    vi.stubEnv('VITE_POSTHOG_HOST', 'https://eu.posthog.com')
    await import('./posthog')
    expect(mockInit).toHaveBeenCalledWith('phc_test123', expect.objectContaining({
      api_host: 'https://eu.posthog.com',
    }))
  })
})

/**
 * Strict GraphQL utilities — re-exports urql hooks with types that reject raw strings.
 *
 * Import useQuery/useMutation from here instead of 'urql'. Raw string queries
 * bypass gql.tada's compile-time schema validation, which has caused production
 * bugs (e.g. querying fields that don't exist in the schema).
 *
 * These wrappers require a parsed DocumentNode (has 'kind' and 'definitions'),
 * which gql.tada's graphql() returns but raw strings do not satisfy.
 *
 * Usage:
 *   import { graphql } from 'gql.tada'
 *   import { useQuery, useMutation } from '@/lib/graphql'
 *
 *   const MyQuery = graphql(`query MyQuery { ... }`)
 *   const [result] = useQuery({ query: MyQuery })
 */

import {
  useQuery as _useQuery,
  useMutation as _useMutation,
  type UseQueryResponse,
  type UseMutationResponse,
  type AnyVariables,
  type OperationContext,
  type RequestPolicy,
} from 'urql'

// A parsed GraphQL document has { kind: 'Document', definitions: [...] }.
// gql.tada's graphql() returns this at runtime. Raw strings don't have these
// properties, so TypeScript rejects them.
interface ParsedDocument {
  readonly kind: string
  readonly definitions: readonly unknown[]
}

interface StrictQueryArgs<Variables extends AnyVariables = AnyVariables> {
  query: ParsedDocument
  variables?: Variables
  requestPolicy?: RequestPolicy
  context?: Partial<OperationContext>
  pause?: boolean
}

// eslint-disable-next-line @typescript-eslint/no-explicit-any
export function useQuery<Data = any, Variables extends AnyVariables = AnyVariables>(
  args: StrictQueryArgs<Variables>,
): UseQueryResponse<Data, Variables> {
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  return _useQuery(args as any)
}

// eslint-disable-next-line @typescript-eslint/no-explicit-any
export function useMutation<Data = any, Variables extends AnyVariables = AnyVariables>(
  query: ParsedDocument,
): UseMutationResponse<Data, Variables> {
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  return _useMutation(query as any)
}

import * as matchers from '@testing-library/jest-dom/matchers'
import { expect, afterEach, vi } from 'vitest'
import { cleanup } from '@testing-library/react'

expect.extend(matchers)

// Cleanup DOM after each test (required when not using vitest globals)
afterEach(() => {
  cleanup()
})

// Global PostHog mocks — prevent network requests and side effects in all tests
vi.mock('posthog-js', () => {
  const posthog = {
    init: vi.fn(),
    capture: vi.fn(),
    identify: vi.fn(),
    reset: vi.fn(),
    debug: vi.fn(),
    register: vi.fn(),
    opt_out_capturing: vi.fn(),
    opt_in_capturing: vi.fn(),
    get_distinct_id: vi.fn().mockReturnValue('test-distinct-id'),
  }
  return { default: posthog, ...posthog }
})

vi.mock('posthog-js/react', () => ({
  PostHogProvider: ({ children }: { children: React.ReactNode }) => children,
  usePostHog: () => ({
    capture: vi.fn(),
    identify: vi.fn(),
    reset: vi.fn(),
  }),
}))

