import { describe, it, expect, vi, beforeEach } from 'vitest'
import { makeOperation, CombinedError } from '@urql/core'
import { GraphQLError } from 'graphql'
import { pipe, fromValue, toPromise } from 'wonka'
import { parse } from 'graphql'

// posthog-js is globally mocked in test/setup.ts
import posthog from 'posthog-js'

// We need to control posthogEnabled per test
vi.mock('./posthog', () => ({
  posthog: (await import('posthog-js')).default,
  posthogEnabled: true,
}))

import * as posthogModule from './posthog'

function makeTestOperation(queryStr: string) {
  return makeOperation('query', {
    key: 1,
    query: parse(queryStr),
    variables: {},
  }, {
    url: '/graphql',
    requestPolicy: 'cache-first',
  })
}

describe('posthogExchange', () => {
  beforeEach(() => {
    vi.clearAllMocks()
  })

  it('captures graphql_error event when result has graphQLErrors', async () => {
    const { posthogExchange } = await import('./posthogExchange')

    const operation = makeTestOperation('query SearchInstitutions { search { total } }')
    const error = new CombinedError({
      graphQLErrors: [new GraphQLError('Something went wrong')],
    })

    const forward = vi.fn().mockImplementation((ops$) =>
      pipe(
        ops$,
        // Replace each operation with a result containing the error
        () => fromValue({ operation, data: null, error, stale: false, hasNext: false }),
      ),
    )

    const exchange = posthogExchange({ forward, client: {} as never })
    const result = await pipe(fromValue(operation), exchange, toPromise)

    expect(result.error).toBe(error)
    expect(posthog.capture).toHaveBeenCalledOnce()
    expect(posthog.capture).toHaveBeenCalledWith('graphql_error', {
      operation_name: 'SearchInstitutions',
      errors: ['Something went wrong'],
    })
  })

  it('does not capture when result has no errors', async () => {
    const { posthogExchange } = await import('./posthogExchange')

    const operation = makeTestOperation('query GetHealth { health }')

    const forward = vi.fn().mockImplementation((ops$) =>
      pipe(
        ops$,
        () => fromValue({ operation, data: { health: 'ok' }, error: undefined, stale: false, hasNext: false }),
      ),
    )

    const exchange = posthogExchange({ forward, client: {} as never })
    await pipe(fromValue(operation), exchange, toPromise)

    expect(posthog.capture).not.toHaveBeenCalled()
  })

  it('captures multiple error messages', async () => {
    const { posthogExchange } = await import('./posthogExchange')

    const operation = makeTestOperation('query Multi { a b }')
    const error = new CombinedError({
      graphQLErrors: [
        new GraphQLError('Error one'),
        new GraphQLError('Error two'),
      ],
    })

    const forward = vi.fn().mockImplementation((ops$) =>
      pipe(
        ops$,
        () => fromValue({ operation, data: null, error, stale: false, hasNext: false }),
      ),
    )

    const exchange = posthogExchange({ forward, client: {} as never })
    await pipe(fromValue(operation), exchange, toPromise)

    expect(posthog.capture).toHaveBeenCalledWith('graphql_error', {
      operation_name: 'Multi',
      errors: ['Error one', 'Error two'],
    })
  })

  it('uses "unknown" when query has no operation name', async () => {
    const { posthogExchange } = await import('./posthogExchange')

    const operation = makeTestOperation('{ health }')
    const error = new CombinedError({
      graphQLErrors: [new GraphQLError('Anon error')],
    })

    const forward = vi.fn().mockImplementation((ops$) =>
      pipe(
        ops$,
        () => fromValue({ operation, data: null, error, stale: false, hasNext: false }),
      ),
    )

    const exchange = posthogExchange({ forward, client: {} as never })
    await pipe(fromValue(operation), exchange, toPromise)

    expect(posthog.capture).toHaveBeenCalledWith('graphql_error', {
      operation_name: 'unknown',
      errors: ['Anon error'],
    })
  })

  it('is a transparent passthrough when posthog is disabled', async () => {
    // Override posthogEnabled to false
    vi.spyOn(posthogModule, 'posthogEnabled', 'get').mockReturnValue(false)

    // Re-import to pick up the mocked value
    vi.resetModules()

    // Re-mock with disabled
    vi.doMock('./posthog', () => ({
      posthog: posthog,
      posthogEnabled: false,
    }))

    const { posthogExchange: disabledExchange } = await import('./posthogExchange')

    const operation = makeTestOperation('query Test { health }')
    const error = new CombinedError({
      graphQLErrors: [new GraphQLError('Should not capture')],
    })

    const forward = vi.fn().mockImplementation((ops$) =>
      pipe(
        ops$,
        () => fromValue({ operation, data: null, error, stale: false, hasNext: false }),
      ),
    )

    const exchange = disabledExchange({ forward, client: {} as never })
    const result = await pipe(fromValue(operation), exchange, toPromise)

    expect(result.error).toBe(error)
    expect(posthog.capture).not.toHaveBeenCalled()
  })
})

