    const error = new CombinedError({
      graphQLErrors: [new GraphQLError('Something went wrong')],
    })

    const forward = vi.fn().mockImplementation((ops$) =>
      pipe(
        ops$,
        // Replace each operation with a result containing the error
        () => fromValue({ operation, data: null, error, stale: false, hasNext: false }),
      ),
    )

